import{_ as t,o as d,c as r,ag as a}from"./chunks/framework.9URR-i38.js";const u=JSON.parse('{"title":"Helpers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/helpers.md","filePath":"guide/helpers.md","lastUpdated":1778507389000}'),o={name:"guide/helpers.md"};function s(n,e,c,p,h,i){return d(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="helpers" tabindex="-1">Helpers <a class="header-anchor" href="#helpers" aria-label="Permalink to &quot;Helpers&quot;">​</a></h1><p>Helpers are standalone, tree-shakeable functions for interacting with requests and responses. They keep the core lightweight — unused helpers are excluded from the final bundle.</p><h2 id="request-helpers" tabindex="-1">Request Helpers <a class="header-anchor" href="#request-helpers" aria-label="Permalink to &quot;Request Helpers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Helper</th><th>Description</th></tr></thead><tbody><tr><td><code>getRequestHeader(event, name)</code></td><td>Get a single request header</td></tr><tr><td><code>getRequestHostName(event, options?)</code></td><td>Get the request hostname (proxy-aware)</td></tr><tr><td><code>getRequestIP(event, options?)</code></td><td>Get the client IP address (proxy-aware)</td></tr><tr><td><code>getRequestProtocol(event, options?)</code></td><td>Get the request protocol (proxy-aware)</td></tr><tr><td><code>getRequestAcceptableContentTypes(event)</code></td><td>Get all acceptable content types</td></tr><tr><td><code>getRequestAcceptableContentType(event, input?)</code></td><td>Get best matching content type</td></tr><tr><td><code>isRequestCacheable(event, modifiedTime)</code></td><td>Check if the client cache is still valid</td></tr><tr><td><code>matchRequestContentType(event, type)</code></td><td>Check request Content-Type</td></tr></tbody></table><h2 id="response-helpers" tabindex="-1">Response Helpers <a class="header-anchor" href="#response-helpers" aria-label="Permalink to &quot;Response Helpers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Helper</th><th>Description</th></tr></thead><tbody><tr><td><code>sendFile(event, opts)</code></td><td>Send a file with range request support</td></tr><tr><td><code>sendRedirect(event, url, statusCode?)</code></td><td>Redirect the client</td></tr><tr><td><code>sendCreated(event, data?)</code></td><td>Send a 201 Created response</td></tr><tr><td><code>sendAccepted(event, data?)</code></td><td>Send a 202 Accepted response</td></tr><tr><td><code>sendStream(event, stream)</code></td><td>Stream data to the client</td></tr><tr><td><code>sendFormat(event, formats)</code></td><td>Content-negotiate and send</td></tr><tr><td><code>createEventStream(event, options?)</code></td><td>Create a Server-Sent Events stream</td></tr><tr><td><code>setResponseCacheHeaders(event, options?)</code></td><td>Set cache-related headers</td></tr><tr><td><code>setResponseHeaderAttachment(event, filename?)</code></td><td>Set Content-Disposition attachment</td></tr><tr><td><code>setResponseHeaderInline(event, filename?)</code></td><td>Set Content-Disposition inline</td></tr><tr><td><code>setResponseHeaderContentType(event, type)</code></td><td>Set Content-Type header</td></tr><tr><td><code>appendResponseHeader(event, name, value)</code></td><td>Append to a response header</td></tr></tbody></table><h2 id="event-properties" tabindex="-1">Event Properties <a class="header-anchor" href="#event-properties" aria-label="Permalink to &quot;Event Properties&quot;">​</a></h2><p>These are accessed directly on the event object, not through helper functions:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>event.request</code></td><td>The underlying <code>ServerRequest</code></td></tr><tr><td><code>event.method</code></td><td>HTTP method (GET, POST, etc.)</td></tr><tr><td><code>event.path</code></td><td>URL path</td></tr><tr><td><code>event.params</code></td><td>Route parameters</td></tr><tr><td><code>event.headers</code></td><td>Request headers (Headers object)</td></tr><tr><td><code>event.searchParams</code></td><td>URL search parameters (URLSearchParams)</td></tr><tr><td><code>event.mountPath</code></td><td>Mount path prefix</td></tr><tr><td><code>event.response</code></td><td>Response accumulator (status, headers, statusText)</td></tr><tr><td><code>event.dispatched</code></td><td>Whether a response has been produced</td></tr><tr><td><code>event.store</code></td><td>Per-request state store for data sharing</td></tr><tr><td><code>event.next()</code></td><td>Continue to the next handler (cached)</td></tr></tbody></table><p>See the <a href="./request">Request</a> and <a href="./response">Response</a> guides for detailed usage.</p>',10)])])}const v=t(o,[["render",s]]);export{u as __pageData,v as default};
